        [NameInMap("UseAdditionalService")]
        [Validation(Required=false)]
        public bool? UseAdditionalService { get; set; }

        /// <summary>
        /// <para>The user data of the instance. The user data must be Base64-encoded. The raw data can be up to 32 KB in size.</para>
        /// 
        /// <b>Example:</b>
        /// <para>ZWNobyBoZWxsbyBlY3Mh</para>
        /// </summary>
        [NameInMap("UserData")]
        [Validation(Required=false)]
        public string UserData { get; set; }

        /// <summary>
        /// <para>When you create an instance in a VPC, you must specify a VSwitch ID. You can call the <a href="https://help.aliyun.com/document_detail/35748.html">DescribeVSwitches</a> operation to query information about the VSwitches that you created.</para>
        /// <remarks>
        /// <para>If <c>VSwitchId</c> is specified, <c>ZoneId</c> must match the VSwitch\&quot;s zone. If <c>ZoneId</c> is left unspecified, the system automatically uses the VSwitch\&quot;s zone.</para>
        /// </remarks>
        /// 
        /// <b>Example:</b>
        /// <para>vsw-bp1s5fnvk4gn2tws0****</para>
        /// </summary>
        [NameInMap("VSwitchId")]
        [Validation(Required=false)]
        public string VSwitchId { get; set; }

        /// <summary>
        /// <para>The ID of the virtual LAN (VLAN).</para>
        /// 
        /// <b>Example:</b>
        /// <para>10</para>
        /// </summary>
        [NameInMap("VlanId")]
        [Validation(Required=false)]
        public string VlanId { get; set; }

        /// <summary>
        /// <para>The ID of the zone to which the instance belongs. For more information, call the <a href="https://help.aliyun.com/document_detail/25610.html">DescribeZones</a> operation to query the list of zones.</para>
        /// <remarks>
        /// <para>If <c>VSwitchId</c> is specified, <c>ZoneId</c> must match the VSwitch\&quot;s zone. If <c>ZoneId</c> is left unspecified, the system automatically uses the VSwitch\&quot;s zone.</para>
        /// </remarks>
        /// <para>Default value: empty, which indicates that the system randomly selects a zone.</para>
        /// 
        /// <b>Example:</b>
        /// <para>cn-hangzhou-g</para>
        /// </summary>
        [NameInMap("ZoneId")]
        [Validation(Required=false)]
